class Node { constructor(v) { this.val=v; this.prev=this.next=null; } }
class Deque {
  constructor() {
    this.head=new Node(0); this.tail=new Node(0);
    this.head.next=this.tail; this.tail.prev=this.head;
  }
  _insert(prev, val) {
    const n=new Node(val); const next=prev.next;
    prev.next=n; n.prev=prev; n.next=next; next.prev=n;
    return n;
  }
  _remove(n) { n.prev.next=n.next; n.next.prev=n.prev; return n.val; }
  append(v) { this._insert(this.tail.prev, v); }
  appendleft(v) { this._insert(this.head, v); }
  pop() { return this._remove(this.tail.prev); }
  popleft() { return this._remove(this.head.next); }
}
